const listProcessTreeRootsByHost = `-- name: ListProcessTreeRootsByHost :many
WITH roots AS (
  SELECT root_pid, MAX(start_ts) AS last_seen
  FROM process_lifecycle
  WHERE host = $2
    AND (
      $3::timestamptz IS NULL OR start_ts <= $3::timestamptz
    )
    AND (
      $4::timestamptz IS NULL OR COALESCE(end_ts, 'infinity'::timestamptz) >= $4::timestamptz
    )
  GROUP BY root_pid
)
SELECT root_pid
FROM roots
ORDER BY last_seen DESC NULLS LAST
LIMIT $1
`

type ListProcessTreeRootsByHostParams struct {
	Limit int32
	Host  string
	Until pgtype.Timestamptz
	Since pgtype.Timestamptz
}

func (q *Queries) ListProcessTreeRootsByHost(ctx context.Context, arg ListProcessTreeRootsByHostParams) ([]pgtype.Int8, error) {
	rows, err := q.db.Query(ctx, listProcessTreeRootsByHost,
		arg.Limit,
		arg.Host,
		arg.Until,
		arg.Since,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []pgtype.Int8
	for rows.Next() {
		var root_pid pgtype.Int8
		if err := rows.Scan(&root_pid); err != nil {
			return nil, err
		}
		items = append(items, root_pid)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

